{"type": "email", "id": "email_001", "subject": "Weekly Team Meeting Schedule", "from": "sofia.rodriguez@elexionauto.com", "from_name": "Sofia Rodriguez", "to": ["john.doe@elexionauto.com", "emily.brown@elexionauto.com", "william.johnson@elexionauto.com", "claire.martin@elexionauto.com", "robert.thompson@elexionauto.com", "linda.garcia@elexionauto.com"], "cc": [], "date": "2022-02-15 10:15:00", "body": "Hello team,

