{"type": "email", "id": "email_002", "subject": "Marketing Budget for Q2", "from": "john.doe@elexionauto.com", "from_name": "John Doe", "to": ["sofia.rodriguez@elexionauto.com"], "cc": ["emily.brown@elexionauto.com"], "date": "2022-02-16 14:30:00", "body": "Hi Sofia,

